<script>
function gid(id){return document.getElementById(id);}

// ── 面板 ──────────────────────────────────────
var fwID=null;
function closeAll(){
  var ps=document.querySelectorAll('.panel');
  for(var i=0;i<ps.length;i++) ps[i].classList.remove('on');
  if(fwID){cancelAnimationFrame(fwID);fwID=null;}
}
function openPanel(tid){
  closeAll();
  var p=gid('p-'+tid);
  if(!p) return;
  p.classList.add('on');
  p.scrollIntoView({behavior:'smooth',block:'nearest'});
  if(tid==='dice') rollDice(1);
  if(tid==='wheel') drawWheel(wA);
  if(tid==='fireworks') initFW();
}

// ── 彩带 ──────────────────────────────────────
function confetti(){
  var cl=['#ff6ec7','#ffd700','#00e5ff','#ff4d6d','#44ffbb','#cc44ff','#ffaa00'];
  for(var i=0;i<60;i++){(function(i){setTimeout(function(){
    var p=document.createElement('div');p.className='cf';
    p.style.cssText='left:'+Math.random()*100+'vw;background:'+cl[Math.floor(Math.random()*cl.length)]+';animation-duration:'+(1.5+Math.random()*2)+'s;animation-delay:'+Math.random()*.4+'s;width:'+(5+Math.random()*7)+'px;height:'+(5+Math.random()*7)+'px;';
    document.body.appendChild(p);
    setTimeout(function(){if(p.parentNode)p.parentNode.removeChild(p);},4000);
  },i*18);})(i);}
