button{font-family:inherit;border:none;-webkit-appearance:none;appearance:none;cursor:pointer;touch-action:manipulation;outline:none;}
input{-webkit-appearance:none;appearance:none;font-family:inherit;outline:none;border:none;}
.app{max-width:480px;margin:0 auto;padding:0 14px 60px;}
.hdr{text-align:center;padding:28px 0 18px;}
.hdr-title{font-size:1.85rem;font-weight:800;background:linear-gradient(90deg,#ff6ec7,#ffd700,#00e5ff,#ff6ec7);background-size:200%;-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;animation:shimmer 3s linear infinite;letter-spacing:2px;display:block;}
@keyframes shimmer{to{background-position:200% center;}}
.hdr-sub{color:rgba(255,255,255,.5);font-size:.8rem;margin-top:4px;letter-spacing:3px;text-transform:uppercase;display:block;}
.grid{display:grid;grid-template-columns:repeat(3,1fr);gap:11px;margin-bottom:14px;}
.card{border-radius:15px;padding:16px 8px 13px;text-align:center;border:1.5px solid rgba(255,255,255,.13);user-select:none;cursor:pointer;}
.card:active{opacity:.75;}
.ci{font-size:1.85rem;display:block;margin-bottom:5px;pointer-events:none;}
.cl{font-size:.75rem;color:rgba(255,255,255,.92);font-weight:600;pointer-events:none;}
.c1{background:linear-gradient(135deg,#3a0d6e,#7b2fff);}
.c2{background:linear-gradient(135deg,#0d4a3a,#00b899);}
.c3{background:linear-gradient(135deg,#6e0d2a,#ff4d6d);}
.c4{background:linear-gradient(135deg,#4a2d00,#ffaa00);}
.c5{background:linear-gradient(135deg,#002a6e,#0099ff);}
.c6{background:linear-gradient(135deg,#2a006e,#cc44ff);}
.c7{background:linear-gradient(135deg,#003a2a,#44ffbb);}
.c8{background:linear-gradient(135deg,#6e1a00,#ff6622);}
.c9{background:linear-gradient(135deg,#1a006e,#5588ff);}
.panel{display:none;background:rgba(255,255,255,.07);border-radius:18px;border:1px solid rgba(255,255,255,.14);padding:18px 14px;margin-bottom:12px;position:relative;}
.panel.on{display:block;}
.pclose{position:absolute;top:11px;right:12px;background:rgba(255,255,255,.12);border-radius:50%;width:26px;height:26px;color:#fff;font-size:13px;line-height:26px;text-align:center;cursor:pointer;}
.ptitle{color:#fff;font-size:.95rem;font-weight:700;margin-bottom:14px;text-align:center;}
.rbtns{display:flex;gap:9px;justify-content:center;}
.bbtn{padding:10px 20px;border-radius:11px;font-size:.88rem;font-weight:700;background:#0099ff;color:#fff;}
.rbtn{padding:10px 20px;border-radius:11px;font-size:.88rem;font-weight:700;background:#ff4d6d;color:#fff;}
.wbtn{display:block;width:100%;padding:12px;border-radius:12px;font-size:.95rem;font-weight:700;}
.gbtn{background:linear-gradient(90deg,#ff6ec7,#ffaa00);color:#1a0533;}
.pubtn{background:linear-gradient(90deg,#5588ff,#cc44ff);color:#fff;}
.gnbtn{background:#00b899;color:#fff;}
.stbtn{background:#ff4d6d;color:#fff;}
.qbox{background:rgba(255,255,255,.08);border-radius:12px;padding:13px;color:#fff;font-size:.92rem;text-align:center;min-height:58px;display:flex;align-items:center;justify-content:center;line-height:1.55;}
.dres{color:#c9a0ff;font-size:1.05rem;font-weight:700;text-align:center;margin:8px 0 12px;}
.dwrap{display:flex;justify-content:center;gap:14px;margin-bottom:10px;min-height:82px;align-items:center;}
.df{width:74px;height:74px;background:linear-gradient(145deg,#f5f5f5,#ddd);border-radius:13px;display:flex;align-items:center;justify-content:center;box-shadow:3px 3px 8px rgba(0,0,0,.5);flex-shrink:0;}
.df.roll{animation:dr .5s ease;}
@keyframes dr{0%,100%{transform:rotate(0) scale(1)}25%{transform:rotate(-20deg) scale(.9)}75%{transform:rotate(20deg) scale(1.1)}}
.wres{color:#ffd700;font-size:.95rem;font-weight:600;text-align:center;margin-top:9px;min-height:22px;}
.fwcvs{width:100%;height:175px;border-radius:12px;background:#000a1a;display:block;}
.cdbig{font-size:2.8rem;font-weight:700;color:#ffd700;letter-spacing:4px;font-family:monospace;text-align:center;margin:8px 0;}
.cdpres{display:flex;gap:7px;justify-content:center;margin-bottom:10px;}
.cdpre{padding:6px 13px;border-radius:18px;border:1.5px solid rgba(255,255,255,.25);background:transparent;color:#fff;font-size:.78rem;cursor:pointer;}
.mball{width:96px;height:96px;border-radius:50%;background:radial-gradient(circle at 35% 35%,#444,#111);margin:0 auto 11px;display:flex;align-items:center;justify-content:center;cursor:pointer;box-shadow:0 0 28px rgba(100,100,255,.45);}
.minn{width:48px;height:48px;border-radius:50%;background:radial-gradient(circle at 40% 40%,#1133ff,#000066);display:flex;align-items:center;justify-content:center;}
.mnum{color:#fff;font-size:1.15rem;font-weight:700;}
.mans{color:#a0c4ff;font-size:.88rem;text-align:center;min-height:22px;font-weight:500;}
.mball.sk{animation:sk .5s ease;}
@keyframes sk{0%,100%{transform:rotate(0)}20%{transform:rotate(-15deg)}40%{transform:rotate(15deg)}60%{transform:rotate(-10deg)}80%{transform:rotate(10deg)}}
.nrow{display:flex;gap:7px;margin-bottom:9px;}
.ninp{flex:1;padding:8px 11px;border-radius:9px;border:1.5px solid rgba(255,255,255,.2);background:rgba(255,255,255,.08);color:#fff;font-size:.88rem;}
.ninp::placeholder{color:rgba(255,255,255,.38);}
.abtn{padding:8px 13px;border-radius:9px;background:#ffaa00;color:#1a0533;font-weight:700;font-size:1rem;}
.tags{display:flex;flex-wrap:wrap;gap:6px;margin-bottom:11px;min-height:28px;}
.tag{background:rgba(255,255,255,.12);border-radius:18px;padding:4px 10px;color:#fff;font-size:.8rem;cursor:pointer;border:none;font-family:inherit;}
.pres{color:#ffd700;font-size:1rem;font-weight:700;text-align:center;margin-top:9px;min-height:24px;}
.rrow{display:flex;gap:7px;align-items:center;margin-bottom:11px;}
.rinp{width:68px;padding:8px 9px;border-radius:9px;border:1.5px solid rgba(255,255,255,.2);background:rgba(255,255,255,.08);color:#fff;font-size:.9rem;text-align:center;}
.rlbl{color:rgba(255,255,255,.58);font-size:.82rem;}
.rres{color:#00e5ff;font-size:2rem;font-weight:700;text-align:center;margin-top:11px;min-height:46px;font-family:monospace;}
.mgrid{display:grid;grid-template-columns:repeat(3,1fr);gap:8px;}
.mb2{padding:12px 6px;border-radius:12px;font-size:1.35rem;background:rgba(255,255,255,.08);}
.mtxt{color:#fff;font-size:.86rem;text-align:center;margin-top:9px;min-height:38px;line-height:1.5;}
.dlbar{margin-top:14px;padding-top:12px;border-top:1px solid rgba(255,255,255,.1);display:grid;grid-template-columns:1fr 1fr;gap:6px;}
.dllbl{grid-column:1/-1;text-align:center;font-size:.68rem;color:rgba(255,255,255,.32);letter-spacing:1px;}
.dlbtn{display:flex;align-items:center;gap:5px;padding:7px 10px;border-radius:9px;border:1px solid rgba(255,255,255,.14);background:rgba(255,255,255,.05);color:#fff;font-size:.7rem;font-weight:500;cursor:pointer;justify-content:center;font-family:inherit;}
.dlbtn.imp{background:rgba(123,47,255,.14);color:#c9a0ff;border-color:rgba(123,47,255,.28);}
.dlbtn.ok{background:rgba(0,184,153,.18)!important;color:#44ffbb!important;border-color:rgba(0,184,153,.38)!important;}
.dlbtn.err{background:rgba(255,77,109,.18)!important;color:#ff8095!important;border-color:rgba(255,77,109,.38)!important;}
.cf{position:fixed;border-radius:2px;pointer-events:none;z-index:999;animation:cfall linear forwards;}
@keyframes cfall{0%{transform:translateY(-20px) rotate(0);opacity:1}100%{transform:translateY(110vh) rotate(720deg);opacity:0}}

html,body{height:100%;overflow-x:hidden;}
.app{padding:10px 14px 30px;}
.panel{display:block!important;margin-bottom:0;}
.grid{display:none!important;}
.hdr{display:none!important;}
</style>
</head>
<body>
<div class="app">
<div class="panel">
  <div class="ptitle">🎭 心情按钮</div>
  <div class="mgrid">
    <button class="mb2" onclick="setMood(0)">😄</button>
    <button class="mb2" onclick="setMood(1)">😑</button>
    <button class="mb2" onclick="setMood(2)">🤩</button>
    <button class="mb2" onclick="setMood(3)">😂</button>
    <button class="mb2" onclick="setMood(4)">🤫</button>
    <button class="mb2" onclick="setMood(5)">😤</button>
  </div>
  <div class="mtxt" id="mt">选一个当前心情，我来给你配上专属氛围！</div>
  <div class="copy-row" id="moodrow" style="display:none;">
    <span class="res-txt" id="moodtxt"></span>
    <button class="cpybtn" id="cpymd" onclick="copyMood()">📋 填入输入框</button>
  </div>
</div>
</div>
<script>
function gid(id){return document.getElementById(id);}
var MM=["🌈 开心的你像阳光！发起一波游戏，把快乐传染给所有人吧！","🥱 无聊？那就转一下幸运转盘，或者来个真心话大冒险！","🚀 这能量要爆炸了！发射烟花庆祝一下吧！","😂 笑声是最好的氛围剂！来一局骰子游戏，输了表演才艺！","🔮 神秘的你最适合摇一摇魔法8号球，窥探命运的答案！","😤 深呼吸，来个倒计时冷静一下，然后用转盘决定下一步！"];
function setMood(i){var txt=MM[i];gid('mt').textContent=txt;gid('moodtxt').textContent=txt;gid('moodrow').style.display='flex';var b=gid('cpymd');b.textContent='📋 填入输入框';b.className='cpybtn';}
function copyMood(){var txt=gid('mt').textContent;if(!txt||txt==='选一个当前心情，我来给你配上专属氛围！')return;if(typeof tavo!=='undefined'&&tavo.input){tavo.input.set(txt);var b=gid('cpymd');b.textContent='✅ 已填入！';b.className='cpybtn ok';setTimeout(function(){b.textContent='📋 填入输入框';b.className='cpybtn';},2000);}else if(navigator.clipboard){navigator.clipboard.writeText(txt).then(function(){var b=gid('cpymd');b.textContent='✅ 已复制！';b.className='cpybtn ok';setTimeout(function(){b.textContent='📋 填入输入框';b.className='cpybtn';},2000);});}
}
</script>
</body>
</html>
